INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 0, 'Given the choice of anyone in the world, whom would you want as a dinner guest?', '["A childhood hero","A historical figure","Someone I''ve lost touch with","A celebrity I admire"]', 1, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 1, 'Would you like to be famous? In what way?', '["Yes — for my talent","Yes — for making a difference","Maybe — just a little known","No — I prefer privacy"]', 1, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 2, 'Before making a phone call, do you ever rehearse what you''re going to say?', '["Every single time","Only for important calls","Rarely","Never — I just wing it"]', 1, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 3, 'What would constitute a perfect day for you?', '["Slow morning, no plans","Adventure from dawn to dusk","Quality time with people I love","Creating something meaningful"]', 0, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 4, 'When did you last sing to yourself? To someone else?', '["Today — I''m always singing","This week, in the shower","Can''t remember honestly","I hum, does that count?"]', 0, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 5, 'If you were able to live to the age of 90 and retain either the mind or body of a 30-year-old, which would you want?', '["The mind, 100%","The body, no question","Mind — my thoughts are me","Body — I''d figure the rest out"]', 0, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 6, 'Do you have a secret hunch about how you will die?', '["Yes, and it''s weirdly specific","I''ve thought about it vaguely","I try not to think about it","No — I''d rather not know"]', 2, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 7, 'Name three things you and your partner appear to have in common.', '["Sense of humor","Values and beliefs","Taste in music or food","How we handle emotions"]', 1, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 8, 'For what in your life do you feel most grateful?', '["My family","My health","The people who chose to stay","The lessons from hard times"]', 0, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 9, 'If you could change anything about the way you were raised, what would it be?', '["More emotional openness","Less pressure to succeed","More quality time together","Nothing — it made me who I am"]', 3, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 10, 'Take four minutes and tell your partner your life story in as much detail as possible.', '["I''d start with childhood","I''d skip to the turning points","I''d focus on who shaped me","I''d struggle to know where to start"]', 2, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 11, 'If you could wake up tomorrow having gained any one quality or ability, what would it be?', '["Unshakeable confidence","Fluency in every language","The ability to read people","Inner peace, no matter what"]', 0, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 12, 'If a crystal ball could tell you the truth about yourself, your life, the future, or anything else, what would you want to know?', '["Will I be happy?","What''s my purpose?","Who truly loves me?","I''d rather not know anything"]', 3, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 13, 'Is there something that you''ve dreamed of doing for a long time? Why haven''t you done it?', '["Yes — fear holds me back","Yes — money is the issue","Yes — timing never felt right","I''m actually living my dream"]', 2, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 14, 'What is the greatest accomplishment of your life?', '["Something career-related","A relationship I built","Surviving something hard","Becoming who I am today"]', 1, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 15, 'What do you value most in a friendship?', '["Honesty, even when it hurts","Loyalty through everything","Showing up without being asked","Being fully yourself around them"]', 0, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 16, 'What is your most treasured memory?', '["A childhood moment","A trip that changed me","A quiet moment with someone","Something I almost forgot until now"]', 3, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 17, 'What is your most terrible memory?', '["A loss I wasn''t ready for","A betrayal I didn''t see coming","A moment I can''t take back","I''d rather not say"]', 2, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 18, 'If you knew that in one year you would die suddenly, would you change anything about the way you are now living? Why?', '["I''d quit my job immediately","I''d tell people how I really feel","I''d travel and stop planning","Honestly? Not much — I''d just be more present"]', 1, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 19, 'What does friendship mean to you?', '["Someone who sees the real me","Being chosen, not obligated","A safe space to fall apart","Growing together, not apart"]', 0, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 20, 'What roles do love and affection play in your life?', '["Everything — I need it to function","Important, but I struggle to show it","I give more than I receive","I''m still learning how to let it in"]', 3, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 21, 'Alternate sharing something you consider a positive characteristic of your partner. Share a total of five items.', '["Their kindness stands out first","Their humor makes everything lighter","Their strength inspires me","Their honesty, even when it''s hard"]', 1, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 22, 'How close and warm is your family? Do you feel your childhood was happier than most other people''s?', '["Very close — I got lucky","Complicated, but loving","Not close — I built my own family","Happy enough, but I don''t compare"]', 2, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 23, 'How do you feel about your relationship with your mother?', '["She''s my best friend","It''s complicated but improving","We''re distant, and that''s okay","It''s something I''m still processing"]', 3, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 24, 'Make three true ''we'' statements each. For instance, ''We are both in this room feeling...''', '["We''re both a little nervous","We''re both more open than usual","We both want this to mean something","We''re both pretending to be chill"]', 0, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 25, 'Complete this sentence: ''I wish I had someone with whom I could share...''', '["My weird, random thoughts","The things I''m afraid of","The silence without it being awkward","My actual unfiltered self"]', 2, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 26, 'If you were going to become a close friend with your partner, what would be important for them to know?', '["I take a while to fully trust","I overthink everything","I care more than I show","I need space but I''ll always come back"]', 1, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 27, 'Tell your partner what you like about them; be very honest this time, saying things you might not say to someone you''ve just met.', '["Your energy makes me comfortable","You listen like you actually care","Something about you feels familiar","I like that you''re not trying too hard"]', 0, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 28, 'Share with your partner an embarrassing moment in your life.', '["Something from school days","A public fail I still cringe at","A text I wish I never sent","Something no one else knows about"]', 3, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 29, 'When did you last cry in front of another person? By yourself?', '["Recently — I don''t hide it","A while ago, and alone","I honestly can''t remember","I cry alone, never in front of others"]', 2, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 30, 'Tell your partner something that you like about them already.', '["Your honesty","The way you make me think","How easy this feels","That you''re actually paying attention"]', 0, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'en', 31, 'What, if anything, is too serious to be joked about?', '["Loss and grief","Someone''s insecurities","Nothing — humor heals everything","It depends on who''s joking"]', 1, NULL, NULL);
