INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnerera', 'th', 5, 'หลังเลิกกัน:', '["เปลี่ยนตัวเองจนเขาเสียดาย","ร้องไห้ เยียวยา เขียน เติบโต — ครบวงจร","บล็อก ลบ รักษาความสงบ","เฉิดฉายให้เห็นแล้วปล่อยให้กรรมจัดการ"]', NULL, NULL, '[{"main_character":2},{"healer":2},{"ride_or_die":2},{"soft_villain":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnerera', 'th', 6, 'ภาษารักในทางปฏิบัติ:', '["ฉันวางแผนเดท เซอร์ไพรส์ สุนทรียะ","ฟัง เปิดพื้นที่ สงบในพายุ","มาไม่ว่าอะไร — ตี 3 ข้ามเมือง ตลอดเวลา","ผลักให้เขาดีขึ้นแม้จะต่อต้าน"]', NULL, NULL, '[{"main_character":2},{"healer":2},{"ride_or_die":2},{"soft_villain":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnerera', 'th', 7, 'จุดอ่อนในเรื่องรักที่ใหญ่ที่สุด (พูดตรงๆ):', '["อยากเป็นจุดสนใจมากไปหน่อย","ให้มากเกินจนหลงตัวเอง","เข้มข้นเกินไปเร็วเกินไป","ทดสอบคนว่าจะอยู่ไหม"]', NULL, NULL, '[{"main_character":2},{"healer":2},{"ride_or_die":2},{"soft_villain":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnerera', 'th', 8, 'ตัวละครที่รู้สึกเหมือนตัวเอง:', '["คนที่ถูกประเมินต่ำแต่ชนะเสมอ","คนเงียบที่หัวใจใหญ่ที่สุด","คนที่ซื่อสัตย์ — ซื่อสัตย์จนเจ็บตัว","ตัวป่วนที่ทุกคนหลงรัก"]', NULL, NULL, '[{"main_character":2},{"healer":2},{"ride_or_die":2},{"soft_villain":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnerera', 'th', 9, 'ในกลุ่มเพื่อน เธอคือ:', '["คนจัดการทุกอย่าง","เพื่อนซัพพอร์ตอารมณ์","คนที่พร้อมสู้เพื่อทุกคน","คนคาดเดาไม่ได้ที่ทุกคนรักอยู่ดี"]', NULL, NULL, '[{"main_character":2},{"healer":2},{"ride_or_die":2},{"soft_villain":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnertype', 'th', 0, 'ตอนเธออารมณ์ไม่ดี คนรักเธอ:', '["ทิ้งทุกอย่างมากอด","เงียบไป แล้วเอาชามาให้ทีหลัง","เขียนข้อความยาวตอนตี 2","ทำมุกบ้าๆ จนเธอยิ้มออก"]', NULL, NULL, '[{"golden_retriever":2},{"dark_academic":2},{"mysterious_poet":2},{"chaos_agent":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnertype', 'th', 1, 'วันเสาร์ในฝันของเขา:', '["ตลาดนัดแล้วทำอาหารด้วยกัน","ร้านหนังสือ กาแฟ ไม่ต้องพูดก็ได้","โรดทริปแบบไม่มีแผนที่","อะไรบ้าๆ — โกคาร์ท คาราโอเกะ ว่ายน้ำตอนดึก"]', NULL, NULL, '[{"golden_retriever":2},{"dark_academic":2},{"mysterious_poet":2},{"chaos_agent":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnertype', 'th', 2, 'เขาส่งข้อความยังไง?', '["เช็คอินตลอด เช้าเย็น","เลือกคำอย่างดี บางทีเหมือนบทกวี","หายไปแล้วส่งวอยซ์ยาวมา","มีม ความวุ่นวาย 47 ข้อความรัวๆ"]', NULL, NULL, '[{"golden_retriever":2},{"dark_academic":2},{"mysterious_poet":2},{"chaos_agent":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnertype', 'th', 3, 'เจอเพลงที่ชอบมาก:', '["เปิดลำโพงแล้วเต้นแบบขำๆ","ส่งให้เธอโดยไม่พิมพ์อะไร","จำเนื้อแล้วร้องเบาๆ","เปิดซ้ำแล้วกลายเป็นบุคลิกใหม่เลย"]', NULL, NULL, '[{"golden_retriever":2},{"dark_academic":2},{"mysterious_poet":2},{"chaos_agent":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnertype', 'th', 4, 'บรรยากาศของเขาในปาร์ตี้:', '["คุยกับทุกคน จำชื่อได้หมด","พิงผนังดูคูลแบบไม่ต้องพยายาม","คุยลึกกับคนเดียวที่มุมห้อง","เริ่มเกมท้า ทำอะไรแตก แล้วขอโทษอย่างน่ารัก"]', NULL, NULL, '[{"golden_retriever":2},{"dark_academic":2},{"mysterious_poet":2},{"chaos_agent":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnertype', 'th', 5, 'เขาบอก ''รักนะ'' ยังไง?', '["พูดออกมาดังๆ บ่อยๆ ไม่ลังเล","ไม่ค่อยพูด — แต่พอพูดมา สัมผัสได้ถึงกระดูก","ผ่านเพลย์ลิสต์ จดหมาย สิ่งที่ทำให้","เซอร์ไพรส์ตอนที่คาดไม่ถึง"]', NULL, NULL, '[{"golden_retriever":2},{"dark_academic":2},{"mysterious_poet":2},{"chaos_agent":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnertype', 'th', 6, 'กรีนแฟล็กที่ใหญ่ที่สุด:', '["จำเรื่องเล็กๆ น้อยๆ ได้","ท้าทายความคิดเธอ","เห็นส่วนที่คนอื่นไม่เคยสังเกต","เปลี่ยนทุกช่วงเวลาน่าเบื่อให้เป็นการผจญภัย"]', NULL, NULL, '[{"golden_retriever":2},{"dark_academic":2},{"mysterious_poet":2},{"chaos_agent":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnertype', 'th', 7, 'ตอนทะเลาะกัน:', '["ขอโทษก่อนแม้จะถูก","ต้องการพื้นที่ แล้วกลับมาพร้อมเหตุผล","เงียบไปแล้วเขียนข้อความมา","ทำให้ดราม่า แล้วคลี่คลายด้วยมุก"]', NULL, NULL, '[{"golden_retriever":2},{"dark_academic":2},{"mysterious_poet":2},{"chaos_agent":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnertype', 'th', 8, 'เพื่อนของเขาอธิบายว่า:', '["คนที่หวานที่สุดเท่าที่รู้จัก","คนฉลาดที่ลึกซึ้งแบบลับๆ","คนลึกลับที่ไม่มีใครเข้าใจหมด","คนที่เปลี่ยนทุกอย่างเป็นความวุ่นวาย"]', NULL, NULL, '[{"golden_retriever":2},{"dark_academic":2},{"mysterious_poet":2},{"chaos_agent":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnertype', 'th', 9, 'อะไรดึงดูดเธอตั้งแต่แรก?', '["ความอบอุ่นและปลอดภัยที่รู้สึกได้","สมองเขา — วิธีคิด","อะไรบางอย่างที่เรียกไม่ถูก — แค่รู้สึกดึงดูด","พลังงาน — ทำให้ทุกอย่างมีชีวิตชีวา"]', NULL, NULL, '[{"golden_retriever":2},{"dark_academic":2},{"mysterious_poet":2},{"chaos_agent":2}]');
