INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('redflags', 'th', 6, 'ไม่มีโซเชียลเลย:', '["Green flag จริงๆ","ซ่อนอะไร","ไวบ์ลึกลับ","ฉันก็เหมือนกัน"]', 0, NULL, NULL);
