INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('redflags', 'th', 9, 'บอก ''ไม่เป็นไร'' แต่เป็น:', '["ถามต่อ","ให้พื้นที่","ฉันก็ทำแบบนั้น","ถ้าทำตลอดคือ red flag"]', 0, 'swipe', NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('selfsabotage', 'th', 0, 'ทุกอย่างกำลังไปได้ดี สมองบอกว่า:', '["''มันจะไม่ยั่งยืน''","''ฉันไม่สมควรได้รับ''","''หาจุดบกพร่องก่อนที่เขาจะเจอ''","''ถ้าฉันสำเร็จแค่โดยบังเอิญ?''"]', NULL, NULL, '[{"doom":2},{"unworthiness":2},{"perfectionism":2},{"impostor":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('selfsabotage', 'th', 1, 'ใกล้จะสำเร็จเรื่องใหญ่:', '["ช้าลงหรือหยุดเลย","หาเรื่องทะเลาะหรือสร้างดราม่า","ยกมาตรฐานจนเอื้อมไม่ถึง","ลดความสำคัญเพื่อไม่ให้คนคาดหวัง"]', NULL, NULL, '[{"doom":2},{"unworthiness":2},{"perfectionism":2},{"impostor":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('selfsabotage', 'th', 2, 'รูปแบบการผัดวันประกันพรุ่ง:', '["รอให้หายนะมาจูงใจ","โน้มน้าวตัวเองว่าไม่สำคัญ","ทำซ้ำจนไม่มีอะไรเสร็จ","กลัวผลลัพธ์จะพิสูจน์ว่าไม่ดีพอ"]', NULL, NULL, '[{"doom":2},{"unworthiness":2},{"perfectionism":2},{"impostor":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('selfsabotage', 'th', 3, 'มีคนชมอย่างจริงใจ:', '["ปัดทิ้งทันที","คิดว่าเขาเป็นมารยาท","หาสิ่งที่เขาพลาด","สงสัยว่าเมื่อไหร่เขาจะรู้ว่าผิด"]', NULL, NULL, '[{"doom":1,"unworthiness":1},{"unworthiness":2},{"perfectionism":2},{"impostor":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('selfsabotage', 'th', 4, 'ความสัมพันธ์กับความสำเร็จ:', '["ชั่วคราวและอันตรายตามมา","สำหรับคนอื่น ไม่ใช่เรา","ไม่เคยพอ — มีอะไรต้องแก้เสมอ","เกิดจากโชค ไม่ใช่ความสามารถ"]', NULL, NULL, '[{"doom":2},{"unworthiness":2},{"perfectionism":2},{"impostor":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('selfsabotage', 'th', 5, 'เมื่อพลาด:', '["เห็นไหม? รู้ว่าเป็นเรื่องเวลา","พิสูจน์สิ่งที่กลัวเกี่ยวกับตัวเอง","เล่นซ้ำสิ่งที่ควรทำไม่หยุด","หวังว่าไม่มีใครสังเกต"]', NULL, NULL, '[{"doom":2},{"unworthiness":2},{"perfectionism":2},{"impostor":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('selfsabotage', 'th', 6, 'จัดการข่าวดียังไง?', '["รอให้อีกรองเท้าตก","รู้สึกผิดที่คนอื่นไม่มี","คิดเรื่องที่ยังไม่ดีทันที","รู้สึกเหมือนคนโกงที่โชคดี"]', NULL, NULL, '[{"doom":2},{"unworthiness":2},{"perfectionism":2},{"impostor":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('selfsabotage', 'th', 7, 'ตัวทำลายล้างภายในกระซิบ:', '["''ความสุขมีราคาเสมอ''","''ไม่สมควรได้สิ่งที่มี''","''ถ้าไม่สมบูรณ์แบบก็เป็นขยะ''","''เขาจะรู้ว่าเราแกล้งทำ''"]', NULL, NULL, '[{"doom":2},{"unworthiness":2},{"perfectionism":2},{"impostor":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('selfsabotage', 'th', 8, 'รูปแบบที่รู้จักในตัวเอง:', '["จากไปก่อนถูกทิ้ง","ทำตัวเล็กเพื่อไม่ให้ใครอิจฉา","ทำงานหนักเกินเพื่อชดเชยความรู้สึกไม่พอ","เงียบเพื่อไม่ให้ใครทดสอบสิ่งที่รู้"]', NULL, NULL, '[{"doom":2},{"unworthiness":2},{"perfectionism":2},{"impostor":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('selfsabotage', 'th', 9, 'ความเชื่อที่ต้องเลิกเรียนรู้:', '["''สิ่งดีๆ ไม่เกิดกับคนอย่างฉัน''","''ต้องหามาซึ่งความรัก''","''อะไรที่น้อยกว่าสมบูรณ์แบบคือล้มเหลว''","''มาถึงตรงนี้แค่เพราะไม่มีใครดูใกล้ๆ''"]', NULL, NULL, '[{"doom":2},{"unworthiness":2},{"perfectionism":2},{"impostor":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('shadow', 'th', 0, 'ลักษณะที่ตัดสินคนอื่นรุนแรงที่สุด:', '["ความเห็นแก่ตัว","ความอ่อนแอ","ความไม่จริงใจ","ความต้องการมากเกิน"]', NULL, NULL, '[{"repressed_selfishness":2},{"repressed_vulnerability":2},{"repressed_authenticity":2},{"repressed_need":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('shadow', 'th', 1, 'เมื่ออยู่คนเดียวไม่มีใครเห็น:', '["ปล่อยตัวขี้เกียจ","ร้องไห้มากกว่าที่คนคิด","ความคิดร้ายกว่าที่ยอมรับ","ต้องการคนมากกว่าที่แสดง"]', NULL, NULL, '[{"repressed_selfishness":2},{"repressed_vulnerability":2},{"repressed_authenticity":2},{"repressed_need":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('shadow', 'th', 2, 'คำชมที่ทำให้อึดอัด:', '["''คุณสมควรได้พัก''","''ไม่เป็นไรที่ไม่เข้มแข็ง''","''ไม่จำเป็นต้องดีตลอดเวลา''","''คุณขอความช่วยเหลือได้''"]', NULL, NULL, '[{"repressed_selfishness":2},{"repressed_vulnerability":2},{"repressed_authenticity":2},{"repressed_need":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('shadow', 'th', 3, 'จินตนาการลับที่รู้สึก ''ผิด'':', '["ทิ้งทุกอย่างแล้วไร้ความรับผิดชอบ","พังทลายต่อหน้าใครสักคน","บอกทุกคนว่าคิดอะไรจริงๆ","ถูกดูแลทุกอย่าง"]', NULL, NULL, '[{"repressed_selfishness":2},{"repressed_vulnerability":2},{"repressed_authenticity":2},{"repressed_need":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('shadow', 'th', 4, 'เวอร์ชันที่น่ากลัวของตัวเอง:', '["คนที่ไม่แคร์ใคร","คนที่พังทลายสิ้นเชิง","คนที่พูดสิ่งโหดร้ายออกมา","คนที่ทำอะไรคนเดียวไม่ได้"]', NULL, NULL, '[{"repressed_selfishness":2},{"repressed_vulnerability":2},{"repressed_authenticity":2},{"repressed_need":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('shadow', 'th', 5, 'ตอนเด็กถูกสอนว่า:', '["เห็นแก่ตัวคือสิ่งเลวร้ายที่สุด","ร้องไห้คือความอ่อนแอ","ต้องใจดีและเข้ากับคนเสมอ","ไม่ควรต้องการใคร"]', NULL, NULL, '[{"repressed_selfishness":2},{"repressed_vulnerability":2},{"repressed_authenticity":2},{"repressed_need":2}]');
