INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('whattheyhide', 'th', 3, 'หลังเดทดีมาก:', '["ส่งข้อความ ''คืนนี้สมบูรณ์แบบ'' ก่อนเราถึงบ้าน","เล่นทุกช่วงเวลาซ้ำ กลัวว่าพูดอะไรแปลกไป","เดินช้าๆ ตั้งใจให้คืนยาวขึ้น","ทำตัวปกติแต่เห็นได้ว่าตื่นเต้นอยู่ข้างใน"]', NULL, NULL, '[{"hopeless_romantic":2},{"secret_overthinker":2},{"soft_protector":2},{"guarded_dreamer":2}]');
