INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('whattheyhide', 'th', 8, 'นอนข้างเธอยังไง:', '["หันหน้าหา แขนโอบ ใกล้สุดเท่าที่จะได้","พลิกไปมา — สมองไม่หยุด","อยู่ระหว่างเธอกับประตู — ตลอด","นอนตะแคง หันหลังแต่มือยื่นหาเธอ"]', NULL, NULL, '[{"hopeless_romantic":2},{"secret_overthinker":2},{"soft_protector":2},{"guarded_dreamer":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('whattheyhide', 'th', 9, 'ถ้าบอกเธอได้สักเรื่อง:', '["''รักเธอมานานกว่าที่คิด''","''คิดมากทุกเรื่องเพราะไม่อยากเสียเธอ''","''อยากแบกทุกอย่างไว้เพื่อเธอจะได้ไม่ต้องเจอ''","''อยากเปิดใจให้เธอแต่ไม่รู้จะทำยังไง''"]', NULL, NULL, '[{"hopeless_romantic":2},{"secret_overthinker":2},{"soft_protector":2},{"guarded_dreamer":2}]');
