INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('worldtaste', 'th', 5, 'เครื่องดื่มสบายใจที่สุดในโลก:', '["ชัย (อินเดีย)","มัทฉะ (ญี่ปุ่น)","กาแฟตุรกี","ออร์ชาตา (เม็กซิโก)"]', 2, NULL, NULL);
