INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('worldtaste', 'th', 8, 'ถ้าอยู่ต่างประเทศ 1 ปี:', '["อิตาลี — อาหารและไวบ์","เกาหลีใต้ — คลื่นวัฒนธรรม","บราซิล — พลังและความอบอุ่น","นิวซีแลนด์ — ธรรมชาติและสงบ"]', 0, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('worldtaste', 'th', 9, 'ประเพณีขนมหวานที่ดีที่สุด:', '["เพสทรีฝรั่งเศส","บากลาวาตุรกี","โมจิญี่ปุ่น","กุหลาบจามุนอินเดีย"]', 1, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 0, 'Dünyadaki herhangi biriyle akşam yemeği yiyebilsen, kim olurdu?', '["Çocukluk kahramanım","Tarihi bir figür","İletişimi kopan biri","Hayran olduğum bir ünlü"]', 1, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 1, 'Ünlü olmak ister misin? Nasıl?', '["Evet — yeteneğimle","Evet — fark yaratarak","Belki — biraz tanınan","Hayır — gizliliği tercih ederim"]', 1, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 2, 'Telefon etmeden önce ne söyleyeceğini prova eder misin?', '["Her seferinde","Sadece önemli aramalarda","Nadiren","Asla — doğaçlama yaparım"]', 1, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 3, 'Mükemmel bir gün senin için nasıl olurdu?', '["Yavaş sabah, plan yok","Şafaktan akşama macera","Sevdiklerimle vakit","Anlamlı bir şey yaratmak"]', 0, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 4, 'En son ne zaman kendi kendine şarkı söyledin? Başkasına?', '["Bugün — hep söylerim","Bu hafta, duşta","Hatırlamıyorum","Mırıldanırım, sayılır mı?"]', 0, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 5, '90 yaşına kadar yaşayıp 30 yaşındaki aklını mı bedenini mi korumak istersin?', '["Aklımı, kesinlikle","Bedenimi, tartışmasız","Aklımı — düşüncelerim benim","Bedenimi — gerisini hallederim"]', 0, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 6, 'Nasıl öleceğine dair gizli bir önsezin var mı?', '["Evet, tuhaf derecede spesifik","Belli belirsiz düşündüm","Düşünmemeye çalışıyorum","Hayır — bilmemeyi tercih ederim"]', 2, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 7, 'Seninle partnerinin ortak gibi görünen üç şeyini say.', '["Mizah anlayışımız","Değerlerimiz ve inançlarımız","Müzik veya yemek zevkimiz","Duygularla başa çıkma şeklimiz"]', 1, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 8, 'Hayatında en çok neye minnettarsın?', '["Aileme","Sağlığıma","Kalmayı seçen insanlara","Zor zamanlardan çıkan derslere"]', 0, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 9, 'Yetiştirilme şeklinde bir şeyi değiştirebilsen, ne olurdu?', '["Daha fazla duygusal açıklık","Daha az başarı baskısı","Daha fazla birlikte vakit","Hiçbir şey — beni ben yapan o"]', 3, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 10, 'Dört dakikada hayat hikayeni mümkün olduğunca detaylı anlat.', '["Çocukluktan başlardım","Dönüm noktalarına atlardım","Beni şekillendirenlere odaklanırdım","Nereden başlayacağımı bilemezdim"]', 2, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 11, 'Yarın bir yetenek veya özellik kazanarak uyanabilsen, ne olurdu?', '["Sarsılmaz özgüven","Her dili akıcı konuşmak","İnsanları okuyabilmek","Ne olursa olsun iç huzur"]', 0, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 12, 'Bir kristal küre sana kendin, hayatın veya gelecek hakkında bir gerçeği söyleyebilse, ne bilmek isterdin?', '["Mutlu olacak mıyım?","Amacım ne?","Beni gerçekten kim seviyor?","Hiçbir şey bilmemeyi tercih ederim"]', 3, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 13, 'Uzun zamandır yapmayı hayal ettiğin bir şey var mı? Neden yapmadın?', '["Evet — korku engelliyor","Evet — para sorunu","Evet — zamanlama hiç uygun olmadı","Aslında hayalimi yaşıyorum"]', 2, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 14, 'Hayatının en büyük başarısı ne?', '["Kariyerle ilgili bir şey","Kurduğum bir ilişki","Zor bir şeyden sağ çıkmak","Bugün olduğum kişi olmak"]', 1, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 15, 'Bir dostlukta en çok neye değer verirsin?', '["Acıtsa bile dürüstlük","Her şeye rağmen sadakat","İstenmeden orada olmak","Yanlarında tamamen kendin olmak"]', 0, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 16, 'En değerli anın hangisi?', '["Çocukluktan bir an","Beni değiştiren bir yolculuk","Biriyle sessiz bir an","Şimdiye kadar unuttuğum bir şey"]', 3, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 17, 'En kötü anın hangisi?', '["Hazır olmadığım bir kayıp","Görmediğim bir ihanet","Geri alamayacağım bir an","Söylememyi tercih ederim"]', 2, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 18, 'Bir yıl içinde aniden öleceğini bilsen, yaşam şeklinde bir şeyi değiştirir misin?', '["Hemen işimi bırakırdım","İnsanlara gerçekten ne hissettiğimi söylerdim","Seyahat eder, planlamayı bırakırdım","Çok değil — sadece daha anı yaşardım"]', 1, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 19, 'Dostluk senin için ne ifade ediyor?', '["Gerçek beni gören biri","Zorunluluk değil, seçim","Dağılabileceğim güvenli bir alan","Birlikte büyümek, ayrılmak değil"]', 0, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 20, 'Aşk ve sevgi hayatında nasıl bir rol oynuyor?', '["Her şey — onsuz yapamam","Önemli ama göstermekte zorlanırım","Aldığımdan fazlasını veririm","İçeri almayı hâlâ öğreniyorum"]', 3, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 21, 'Partnerinin olumlu bir özelliğini paylaş. Toplam beş madde paylaşın.', '["İlk göze çarpan nezaketi","Mizahı her şeyi hafifletiyor","Gücü bana ilham veriyor","Dürüstlüğü, zor olsa bile"]', 1, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 22, 'Ailen ne kadar yakın ve sıcak? Çocukluğunun çoğu insandan daha mutlu olduğunu düşünür müsün?', '["Çok yakın — şanslıyım","Karmaşık ama sevgi dolu","Yakın değil — kendi ailemi kurdum","Yeterince mutlu, karşılaştırmam"]', 2, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 23, 'Annenle ilişkin hakkında ne hissediyorsun?', '["O benim en yakın arkadaşım","Karmaşık ama iyileşiyor","Uzağız ve sorun yok","Hâlâ üzerinde çalıştığım bir şey"]', 3, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 24, 'Üçer tane ''biz'' cümlesi kurun. Örneğin: ''İkimiz de bu odada hissediyoruz ki...''', '["İkimiz de biraz gerginiz","İkimiz de normalden açığız","İkimiz de bunun anlamlı olmasını istiyoruz","İkimiz de sakin görünmeye çalışıyoruz"]', 0, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 25, 'Bu cümleyi tamamla: ''Keşke paylaşabileceğim birim olsa...''', '["Garip, rastgele düşüncelerimi","Korktuğum şeyleri","Gariplik olmadan sessizliği","Filtresiz gerçek benliğimi"]', 2, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 26, 'Partnerinle yakın arkadaş olacak olsan, bilmesi gereken önemli şey ne?', '["Tam güvenmem zaman alır","Her şeyi aşırı düşünürüm","Gösterdiğimden fazla önemserim","Alana ihtiyacım var ama hep dönerim"]', 1, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 27, 'Partnerinde neyi sevdiğini söyle; bu sefer çok dürüst ol.', '["Enerjin beni rahatlatıyor","Gerçekten önemsiyormuş gibi dinliyorsun","Sende tanıdık bir şey var","Fazla çabalamaman hoşuma gidiyor"]', 0, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 28, 'Hayatından utanç verici bir anı paylaş.', '["Okul günlerinden bir şey","Hâlâ utandığım halka açık bir başarısızlık","Keşke göndermesem dediğim bir mesaj","Kimsenin bilmediği bir şey"]', 3, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 29, 'En son ne zaman birinin önünde ağladın? Yalnızken?', '["Yakın zamanda — saklamam","Uzun zaman önce, yalnızdım","Gerçekten hatırlamıyorum","Yalnız ağlarım, başkalarının önünde asla"]', 2, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 30, 'Partnerinde şimdiden sevdiğin bir şeyi söyle.', '["Dürüstlüğün","Beni düşündürme şeklin","Bunun ne kadar kolay hissettirdiği","Gerçekten dikkat etmen"]', 0, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 31, 'Şaka yapılamayacak kadar ciddi olan bir şey var mı?', '["Kayıp ve yas","Birinin güvensizlikleri","Hiçbir şey — mizah her şeyi iyileştirir","Kimin şaka yaptığına bağlı"]', 1, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 32, 'Bu akşam kimseyle iletişim kuramadan ölecek olsan, birine söylemediğin için en çok neyi pişman olurdun?', '["Onu sevdiğimi","Özür dilediğimi","Hayatımı değiştirdiğini","Onunla gurur duyduğumu"]', 3, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 33, 'Evin yanıyor. Sevdiklerini kurtardıktan sonra bir eşya için son şansın var. Ne alırdın?', '["Fotoğraflar ve anılar","Kaybettiğim birinden kalan bir şey","Günlüğüm veya mektuplarım","Telefonum — her şey onda"]', 2, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 34, 'Ailende kimin ölümü seni en çok sarsardı? Neden?', '["Anne/babam — hazır değilim","Kardeşim — beni en iyi o tanır","Büyükannem/babam — beni şekillendirdiler","Bunu düşünemiyorum bile"]', 3, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('36questions', 'tr', 35, 'Kişisel bir sorununu paylaş ve partnerinden nasıl çözeceğini sor.', '["Kariyer yolum hakkında","Yönetmeye çalıştığım bir ilişki","Henüz yüzleşmediğim bir korku","Öz değerimle ilgili bir şey"]', 2, NULL, NULL);
