INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('livingtogether', 'tr', 0, 'Bu akşam kim yemek yapıyor?', '["Ben yaparım","Sen pişir, ben toplayım","Sipariş verelim","Hangimiz daha az yorgunsa"]', 3, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('livingtogether', 'tr', 1, 'Termostat tartışması:', '["Hep üşürüm, battaniye insanıyım","Hep sıcak, pencere açık","Bir şekilde uzlaşırız","Son dokunan kazanır"]', 2, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('livingtogether', 'tr', 2, 'İdeal uyku düzeni:', '["Aynı yatak, sarılarak","Aynı yatak, ayrı battaniye","Aynı oda, ayrı yatak","Bazen kendi alanım lazım"]', 1, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('livingtogether', 'tr', 3, 'Ev işlerini nasıl hallediyorsun?', '["Sıkı program","Gören yapar","Haftalık sırayla","Her seferinde tartışırız"]', 1, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('livingtogether', 'tr', 4, 'Market alışverişi felsefesi:', '["Yemek planı ve liste","Reyonlarda gezin","Sadece online sipariş","Atıştırmalık al, yemeği sonra düşün"]', 3, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('livingtogether', 'tr', 5, 'Banyo durumu:', '["En az 45 dakika lazım","Gir çık, 10 dakika","Paylaşabiliriz, sorun yok","Orada benimle konuşma"]', 3, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('livingtogether', 'tr', 6, 'TV kumanda kontrolü:', '["Ben seçerim, sen kabul et","Sırayla","30 dk gezin, hiçbir şey izleme","Ayrı ekranlar dürüst olmak gerekirse"]', 2, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('livingtogether', 'tr', 7, 'Misafir geldiğinde:', '["Her yeri derinlemesine temizle","Hızlı toparlama yeter","Evimiz, dağınıklığımız","En az 3 gün önceden haber lazım"]', 3, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('livingtogether', 'tr', 8, 'Sabah rutini uyumu:', '["Birlikte uyanırız","Birimiz zombi","Tamamen farklı saatler","Kahveye kadar sessiz birlikte var olma"]', 3, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('livingtogether', 'tr', 9, 'Evde para konuşması:', '["Her şeyi yarı yarıya böl","Tek hesap, her şey ortak","Herkes güçlü olduğu yeri öder","Bu konuyu yeterince konuşmuyoruz"]', 0, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('lovelang', 'tr', 0, 'Berbat bir gün geçirdin. Seni en çabuk ne iyileştirir?', '["Sessiz uzun bir sarılma","''Seninle gurur duyuyorum'' duymak","Birinin bulaşıkları yıkaması","Yastığında sürpriz bir hediye","Telefonlar kapalı, bütün bir akşam birlikte"]', NULL, NULL, '[{"touch":2},{"words":2},{"acts":2},{"gifts":2},{"time":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('lovelang', 'tr', 1, 'Partnerin doğum gününü unuttu. En çok ne acıtır?', '["Kutlama mesajı yok","Plan yapma çabası yok","Hediye yok","İzin almadı","Sarılma bile yok"]', NULL, NULL, '[{"words":2},{"acts":2},{"gifts":2},{"time":2},{"touch":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('lovelang', 'tr', 2, 'Seni en çok ne sevilmiş hissettirir?', '["Herkesin içinde elimi tutması","Gerçek, içten bir mesaj yazması","Korktuğum bir işi halletmesi","Küçük rastgele bir şey getirmesi","Sırf benimle olmak için planlarını iptal etmesi"]', NULL, NULL, '[{"touch":2},{"words":2},{"acts":2},{"gifts":2},{"time":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('lovelang', 'tr', 3, 'En romantik jest:', '["Mutfakta dans etmek","El yazısıyla mektup","Sormadan arabamı yıkaması","Sadece bana özel playlist","Hiçbir dikkat dağıtıcı olmadan bütün bir gün"]', NULL, NULL, '[{"touch":2},{"words":2},{"acts":2},{"gifts":2},{"time":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('lovelang', 'tr', 4, 'Birine aşık oluyorsun. İlk işaret?', '["Fiziksel olarak yakın olmak istiyorum","Sürekli iltifat etmeye başlıyorum","Hayatını kolaylaştırmak için şeyler yapıyorum","Hoşuna gidecek şeyleri fark edip alıyorum","Yanında zamanın nasıl geçtiğini anlamıyorum"]', NULL, NULL, '[{"touch":2},{"words":2},{"acts":2},{"gifts":2},{"time":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('lovelang', 'tr', 5, 'Kavgada barışmanın en hızlı yolu:', '["Sadece sarıl bana","Özür dile ve ciddi ol","Göster, söyleme","Barış teklifi — çiçek, yemek, bir şey","Biz iyiyiz olana kadar yanımda kal"]', NULL, NULL, '[{"touch":2},{"words":2},{"acts":2},{"gifts":2},{"time":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('lovelang', 'tr', 6, 'Partnerden en çok ne incitir?', '["Bana hiç dokunmaması","Hissettiklerini söylememesi","Her şeyi tek başıma halletmem","Dışarıdayken beni düşünmemesi","Benim için hiç zamanı olmaması"]', NULL, NULL, '[{"touch":2},{"words":2},{"acts":2},{"gifts":2},{"time":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('lovelang', 'tr', 7, 'Arkadaşlarına sevgini nasıl gösterirsin?', '["Sarılmalar, kol dokunuşları","Övgü ve yüksek sesle söyleme","Taşınmalarına yardım, onları bir yere bırakma","Bahsettikleri şeyi hatırlayıp alma","Gelip zamanımı verme"]', NULL, NULL, '[{"touch":2},{"words":2},{"acts":2},{"gifts":2},{"time":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('lovelang', 'tr', 8, 'Biriyle mükemmel sabahın:', '["İç içe uyanmak","Yanımızdayken bile tatlı sabah mesajları","Kahve ve kahvaltıyı hazırlamış olması","Komodinin üstünde küçük bir not","Gidecek yer yok — sadece biz, bütün sabah"]', NULL, NULL, '[{"touch":2},{"words":2},{"acts":2},{"gifts":2},{"time":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('lovelang', 'tr', 9, 'Sevgi bir dil olsaydı, seninki:', '["Tene temas","Unutulmayan sözler","Sözlerden güçlü eylemler","Şeyin arkasındaki düşünce","Bölünmemiş varlık"]', NULL, NULL, '[{"touch":2},{"words":2},{"acts":2},{"gifts":2},{"time":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnerera', 'tr', 0, 'Bir arkadaşın zor günler geçiriyorsa:', '["Devralırım — toparlanma planı hazır","Yargılamadan saatlerce dinlerim","Atıştırmalıkla kapıda beliririm","İhtiyacı olan sert gerçeği söylerim"]', NULL, NULL, '[{"main_character":2},{"healer":2},{"ride_or_die":2},{"soft_villain":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnerera', 'tr', 1, 'Instagram story enerjin:', '["Küratörlü, estetik, hiçbir şey belli etmez","Sıcak, yumuşak, huzurlu","En yakınını 12 emoji ile paylaşırsın","Cesur fikirler ve filtresiz yorumlar"]', NULL, NULL, '[{"main_character":2},{"healer":2},{"ride_or_die":2},{"soft_villain":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnerera', 'tr', 2, 'Yazışma aşamasında ne yaparsın?', '["Tempoyu ben belirlerim — peşimden gelsin ya da gitsin","Enerjisine uyar, sabırlı kalırım","Hemen all-in olurum, oyun yok","Biri kendini kanıtlayana kadar seçenekleri açık tutarım"]', NULL, NULL, '[{"main_character":2},{"healer":2},{"ride_or_die":2},{"soft_villain":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnerera', 'tr', 3, 'İlişkideki süper gücün:', '["Onu da başrol gibi hissettirmek","Söylemeden önce neye ihtiyacı olduğunu bilmek","Kıyameti bile atlatacak sadakat","Sıkılmasına asla izin vermemek"]', NULL, NULL, '[{"main_character":2},{"healer":2},{"ride_or_die":2},{"soft_villain":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnerera', 'tr', 4, 'Eski sevgilin seni nasıl tanımlar:', '["Kaçırdığı kişi","Çok iyi seven","Her şeyi yapacak olan","Onu sarsan kişi"]', NULL, NULL, '[{"main_character":2},{"healer":2},{"ride_or_die":2},{"soft_villain":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnerera', 'tr', 5, 'Ayrılıktan sonra:', '["Öyle bir değişirim ki pişman olurlar","Ağlarım, iyileşirim, yazarım, büyürüm — tam döngü","Engelle, sil, huzurumu koru","Göz önünde parlayıp karmaya bırakırım"]', NULL, NULL, '[{"main_character":2},{"healer":2},{"ride_or_die":2},{"soft_villain":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnerera', 'tr', 6, 'Sevgi dilin pratikte:', '["Buluşmaları, sürprizleri, estetiği ben planlarım","Dinlerim, alan açarım, fırtınada sakin kalırım","Ne olursa olsun gelirim — gece 3, şehrin öbür ucu, her zaman","Dirense bile daha iyi olmaya iterim"]', NULL, NULL, '[{"main_character":2},{"healer":2},{"ride_or_die":2},{"soft_villain":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnerera', 'tr', 7, 'En büyük ilişki kusurun (dürüst ol):', '["İlgi merkezini biraz fazla seviyorum","Çok verip kendimi kaybediyorum","Çok yoğunum çok erken","İnsanları kalıp kalmayacaklarını görmek için test ediyorum"]', NULL, NULL, '[{"main_character":2},{"healer":2},{"ride_or_die":2},{"soft_villain":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnerera', 'tr', 8, 'Kendine yakın hissettiğin karakter:', '["Hafife alınan ama hep kazanan","En büyük kalbi olan sessiz kişi","Sonuna kadar sadık — hata yapacak kadar","Herkesin takıntılı olduğu joker"]', NULL, NULL, '[{"main_character":2},{"healer":2},{"ride_or_die":2},{"soft_villain":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnerera', 'tr', 9, 'Arkadaş grubunda sen:', '["Her şeyi organize eden","Duygusal destek arkadaşı","Herhangi biri için kavga edecek olan","Yine de sevdikleri tahmin edilemez kişi"]', NULL, NULL, '[{"main_character":2},{"healer":2},{"ride_or_die":2},{"soft_villain":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnertype', 'tr', 0, 'Sen üzgünken partnerin:', '["Her şeyi bırakıp sarılır","Sessizleşir, sonra çay getirir","Gece 2''de uzun bir mesaj yazar","Gülene kadar saçma şakalar yapar"]', NULL, NULL, '[{"golden_retriever":2},{"dark_academic":2},{"mysterious_poet":2},{"chaos_agent":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnertype', 'tr', 1, 'Onun ideal cumartesisi:', '["Pazar ve birlikte yemek yapmak","Kitapçı, kahve, sessizlik yeterli","Haritasız spontane bir yolculuk","Çılgınca bir şey — go-kart, karaoke, gece yarısı yüzme"]', NULL, NULL, '[{"golden_retriever":2},{"dark_academic":2},{"mysterious_poet":2},{"chaos_agent":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnertype', 'tr', 2, 'Sana nasıl mesaj atar?', '["Sürekli kontrol, sabah akşam","Dikkatle yazılmış, bazen şiirsel","Kaybolur sonra sesli mesaj denemesi gönderir","Memler, kaos, art arda 47 mesaj"]', NULL, NULL, '[{"golden_retriever":2},{"dark_academic":2},{"mysterious_poet":2},{"chaos_agent":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnertype', 'tr', 3, 'Sevdiği bir şarkı bulunca:', '["Hoparlörden açar ve kötü dans eder","Sana açıklama yapmadan gönderir","Sözlerini öğrenip sessizce söyler","Tekrara alır ve bütün kişiliği o şarkı olur"]', NULL, NULL, '[{"golden_retriever":2},{"dark_academic":2},{"mysterious_poet":2},{"chaos_agent":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnertype', 'tr', 4, 'Partideki hali:', '["Herkesle konuşur, her ismi hatırlar","Duvara yaslanıp zahmetsizce cool görünür","Köşede biriyle derin sohbet","Cesaret oyunu başlatır, bir şey kırar, tatlılıkla özür diler"]', NULL, NULL, '[{"golden_retriever":2},{"dark_academic":2},{"mysterious_poet":2},{"chaos_agent":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnertype', 'tr', 5, '''Seni seviyorum'' nasıl der?', '["Yüksek sesle, sık sık, tereddütsüz","Nadiren — ama dediğinde kemiklerine kadar hissedersin","Playlistler, mektuplar, yaptığı şeylerle","En beklemediğin anda sürprizle"]', NULL, NULL, '[{"golden_retriever":2},{"dark_academic":2},{"mysterious_poet":2},{"chaos_agent":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnertype', 'tr', 6, 'En büyük yeşil bayrağı:', '["Küçük şeyleri hatırlaması","Seni entelektüel olarak zorlaması","Kimsenin fark etmediği yanlarını görmesi","Her sıkıcı anı maceraya çevirmesi"]', NULL, NULL, '[{"golden_retriever":2},{"dark_academic":2},{"mysterious_poet":2},{"chaos_agent":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnertype', 'tr', 7, 'Kavga ettiğinizde:', '["Haklı olsa bile ilk o özür diler","Alana ihtiyaç duyar, sonra tezle döner","Sessizleşir ve sana mesaj yazar","Dramatikleştirir, sonra espriyle çözer"]', NULL, NULL, '[{"golden_retriever":2},{"dark_academic":2},{"mysterious_poet":2},{"chaos_agent":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnertype', 'tr', 8, 'Arkadaşları onu nasıl tanımlar:', '["Tanıdıkları en tatlı insan","Gizliden derin olan akıllı biri","Kimsenin tam anlayamadığı gizemli biri","Her şeyi kaosa çeviren kişi"]', NULL, NULL, '[{"golden_retriever":2},{"dark_academic":2},{"mysterious_poet":2},{"chaos_agent":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('partnertype', 'tr', 9, 'Onda seni ilk çeken ne oldu?', '["Ne kadar güvenli ve sıcak hissettirdiği","Zihni — düşünme şekli","Adını koyamadığın bir çekim","Enerjisi — her şeyi elektrikli yapıyordu"]', NULL, NULL, '[{"golden_retriever":2},{"dark_academic":2},{"mysterious_poet":2},{"chaos_agent":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('redflags', 'tr', 0, '3 gün sonra cevap yazıyor:', '["Red flag","Belki meşguldür"]', 0, 'vs', NULL);
