INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('redflags', 'tr', 2, 'Her şeyi sosyal medyaya atıyor:', '["Özgüvene bak","Büyük red flag","Ben de varım yeter","Ben de aynısını yaparım"]', 1, 'bubble', NULL);
