INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('redflags', 'tr', 5, 'Hiç plan yapmıyor:', '["Red flag","Belki utangaçtır","Plancı zaten benim","Hiç buluşamayız"]', 0, NULL, NULL);
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('redflags', 'tr', 6, 'Hiç sosyal medyası yok:', '["Green flag aslında","Ne saklıyor","Gizemli vibes","Ben de öyle"]', 0, NULL, NULL);
