INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('selfsabotage', 'tr', 0, 'Her şey iyi gidiyor. Beynin diyor ki:', '["''Bu sürmeyecek''","''Bunu hak etmiyorum''","''Onlar bulmadan bir kusur bulayım''","''Ya sadece tesadüfen başarılıysam?''"]', NULL, NULL, '[{"doom":2},{"unworthiness":2},{"perfectionism":2},{"impostor":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('selfsabotage', 'tr', 1, 'Büyük bir başarıya yakınsın:', '["Yavaşlarım ya da tamamen dururum","Kavga çıkarırım ya da drama yaratırım","Çıtayı ulaşamayacağım kadar yükseltirim","Kimse daha fazla beklemesin diye küçümserim"]', NULL, NULL, '[{"doom":2},{"unworthiness":2},{"perfectionism":2},{"impostor":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('selfsabotage', 'tr', 2, 'Erteleme kalıbın:', '["Felaketin motive etmesini beklerim","Zaten önemli olmadığına kendimi ikna ederim","Her şeyi yeniden yaparım, hiçbir şey bitmez","Sonucun yeterli olmadığımı kanıtlamasından korkuyorum"]', NULL, NULL, '[{"doom":2},{"unworthiness":2},{"perfectionism":2},{"impostor":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('selfsabotage', 'tr', 3, 'Biri gerçek bir iltifat veriyor:', '["Hemen savuştururum","Kibarlık ettiklerini düşünürüm","Kaçırdıkları bir şey bulurum","Yanıldıklarını ne zaman anlayacaklarını merak ederim"]', NULL, NULL, '[{"doom":1,"unworthiness":1},{"unworthiness":2},{"perfectionism":2},{"impostor":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('selfsabotage', 'tr', 4, 'Başarıyla ilişkin:', '["Geçici ve tehlike takip eder","Başkaları için, benim için değil","Asla yeterli değil — hep düzeltecek daha fazla var","Liyakatle değil, şansla oldu"]', NULL, NULL, '[{"doom":2},{"unworthiness":2},{"perfectionism":2},{"impostor":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('selfsabotage', 'tr', 5, 'Hata yaptığında:', '["Gördün mü? Sadece zaman meselesiydi","Bu benim hakkımda hep korktuğum şeyi kanıtlıyor","Ne yapmalıydım diye tekrar tekrar oynatırım","Umarım kimse fark etmemiştir"]', NULL, NULL, '[{"doom":2},{"unworthiness":2},{"perfectionism":2},{"impostor":2}]');
INSERT INTO questions (pack_key, lang, sort_order, q, options, pi, format, traits) VALUES ('selfsabotage', 'tr', 6, 'İyi haberle nasıl başa çıkarsın?', '["Diğer ayakkabının düşmesini bekle","Başkalarında yok diye suçluluk duy","Hâlâ doğru olmayan şeyi düşün","Şanslı bir dolandırıcı gibi hisset"]', NULL, NULL, '[{"doom":2},{"unworthiness":2},{"perfectionism":2},{"impostor":2}]');
